    19→import { Switch } from "@/components/ui/switch";
    20→import { useChartTheme } from "@/hooks/useChartTheme";
    21→import { ChartLegend } from "./ChartLegend";
    22→
    23→const MAX_SERIES = 14;
    24→const OTHER_COLOR = "#9ca3af";
    25→
    26→interface LearningsTrendChartProps {
    27→	data: Record<string, string | number>[];
    28→	splitBy: "user_id" | "repository";
    29→	onSplitByChange: (splitBy: "user_id" | "repository") => void;
    30→	userMap?: Record<string, string>;
    31→}
    32→
    33→const COLORS = [
    34→	"#3b82f6",
    35→	"#10b981",
    36→	"#f59e0b",
    37→	"#8b5cf6",
    38→	"#ef4444",
    39→	"#06b6d4",
    40→	"#ec4899",
    41→	"#14b8a6",
    42→	"#f97316",
    43→	"#6366f1",
    44→	"#84cc16",
    45→	"#a855f7",
    46→	"#f43f5e",
    47→	"#0ea5e9",
    48→];
    49→
    50→export function LearningsTrendChart({
    51→	data,
    52→	splitBy,
    53→	onSplitByChange,
    54→	userMap,
    55→}: LearningsTrendChartProps) {
    56→	const { tooltipBg, tooltipBorder, gridStroke } = useChartTheme();
    57→	const [isCumulative, setIsCumulative] = useState(true);
    58→	const [hiddenSeries, setHiddenSeries] = useState<Set<string>>(new Set());
    59→	const toggleSeries = (key: string) =>
    60→		setHiddenSeries((prev) => {
    61→			const next = new Set(prev);
    62→			next.has(key) ? next.delete(key) : next.add(key);
    63→			return next;
    64→		});
    65→
    66→	// All series keys from the data
    67→	const allSeriesKeys = useMemo(() => {
    68→		if (data.length === 0) return [];
    69→		const keys = new Set<string>();
    70→		for (const item of data) {
    71→			for (const key of Object.keys(item)) {
    72→				if (key !== "date") keys.add(key);
    73→			}
    74→		}
    75→		return Array.from(keys).sort();
    76→	}, [data]);
    77→
    78→	// Cap at MAX_SERIES, rest → "Other"
    79→	const { seriesKeys, hasOther } = useMemo(() => {
    80→		if (allSeriesKeys.length <= MAX_SERIES) {
    81→			return { seriesKeys: allSeriesKeys, hasOther: false };
    82→		}
    83→		// Rank by total value across all dates
    84→		const totals = new Map<string, number>();
    85→		for (const item of data) {
    86→			for (const key of allSeriesKeys) {
    87→				totals.set(key, (totals.get(key) ?? 0) + ((item[key] as number) || 0));
    88→			}
    89→		}
    90→		const sorted = Array.from(totals.entries()).sort((a, b) => b[1] - a[1]);
    91→		return {
    92→			seriesKeys: sorted.slice(0, MAX_SERIES).map(([k]) => k),
    93→			hasOther: true,
    94→		};
    95→	}, [allSeriesKeys, data]);
    96→
    97→	const filledData = useMemo(() => {
    98→		if (data.length === 0) return [];
    99→
   100→		const existingDates = Array.from(
   101→			new Set(data.map((d) => d.date as string)),
   102→		).sort();
   103→		const minDate = new Date(existingDates[0]);
   104→		const maxDate = new Date(existingDates[existingDates.length - 1]);
   105→		const dateRange: string[] = [];
   106→		for (let d = new Date(minDate); d <= maxDate; d.setDate(d.getDate() + 1)) {
   107→			dateRange.push(d.toISOString().split("T")[0]);
   108→		}
   109→
   110→		const dataByDate = new Map(data.map((item) => [item.date as string, item]));
   111→		const topKeysSet = new Set(seriesKeys);
   112→
   113→		return dateRange.map((dateKey) => {
   114→			const item = dataByDate.get(dateKey);
   115→			const entry: Record<string, string | number> = { date: dateKey };
   116→			for (const key of seriesKeys) {
   117→				entry[key] = item ? (item[key] as number) || 0 : 0;
   118→			}
   119→			if (hasOther) {
   120→				entry.Other = item
   121→					? allSeriesKeys
   122→							.filter((k) => !topKeysSet.has(k))
   123→							.reduce((sum, k) => sum + ((item[k] as number) || 0), 0)
   124→					: 0;
   125→			}
   126→			return entry;
   127→		});
   128→	}, [data, seriesKeys, allSeriesKeys, hasOther]);
   129→
   130→	const displayKeys = hasOther ? [...seriesKeys, "Other"] : seriesKeys;
   131→
   132→	const chartData = useMemo(() => {
   133→		if (!isCumulative) {
   134→			return filledData.map((item) => ({
   135→				...item,
   136→				displayDate: new Date(item.date as string).toLocaleDateString("en-US", {
   137→					month: "short",
   138→					day: "numeric",
   139→				}),
   140→			}));
   141→		}
   142→
   143→		const cumulativeData = [];
   144→		const runningTotals: Record<string, number> = {};
   145→		for (const key of displayKeys) {
   146→			runningTotals[key] = 0;
   147→		}
   148→
   149→		for (const item of filledData) {
   150→			const cumulativeItem: Record<string, unknown> = {
   151→				date: item.date,
   152→				displayDate: new Date(item.date as string).toLocaleDateString("en-US", {
   153→					month: "short",
   154→					day: "numeric",
   155→				}),
   156→			};
   157→			for (const key of displayKeys) {
   158→				runningTotals[key] += (item[key] as number) || 0;
   159→				cumulativeItem[key] = runningTotals[key];
   160→			}
   161→			cumulativeData.push(cumulativeItem);
   162→		}
   163→
   164→		return cumulativeData;
   165→	}, [filledData, isCumulative, displayKeys]);
   166→
   167→	const getDisplayName = (key: string): string => {
   168→		if (key === "Other") return "Other";
   169→		if (splitBy === "user_id" && userMap) {
   170→			return userMap[key] || `${key.substring(0, 12)}...`;
   171→		}
   172→		return key;
   173→	};
   174→
   175→	return (
   176→		<div className="space-y-4">
   177→			<div className="flex flex-wrap items-center justify-end gap-4">
   178→				<div className="flex items-center gap-2">
   179→					<Select
