    13→import { useChartTheme } from "@/hooks/useChartTheme";
    14→import { formatUsername } from "@/lib/format";
    15→import { ChartLegend } from "./ChartLegend";
    16→
    17→function formatCompactNumber(value: number): string {
    18→	if (value >= 1000000)
    19→		return `${(value / 1000000).toFixed(1).replace(/\.0$/, "")}M`;
    20→	if (value >= 1000) return `${(value / 1000).toFixed(1).replace(/\.0$/, "")}K`;
    21→	return value.toString();
    22→}
    23→
    24→function formatNumberWithCommas(value: number): string {
    25→	return value.toLocaleString();
    26→}
    27→
    28→interface DimensionAnalysisChartProps {
    29→	data: DimensionAnalysisDataPoint[];
    30→	dimension: string;
    31→	metric: string;
    32→	split_by?: string;
    33→	showPercentage?: boolean;
    34→	userMap?: Record<string, string>;
    35→}
    36→
    37→const CHART_COLORS = [
    38→	"#3b82f6",
    39→	"#10b981",
    40→	"#f59e0b",
    41→	"#8b5cf6",
    42→	"#ef4444",
    43→	"#06b6d4",
    44→	"#f97316",
    45→	"#ec4899",
    46→	"#14b8a6",
    47→	"#6366f1",
    48→];
    49→
    50→function formatMetricLabel(metric: string): string {
    51→	const labelMap: Record<string, string> = {
    52→		session_count: "Session Count",
    53→		avg_duration: "Avg Duration (min)",
    54→		total_duration: "Total Duration (hours)",
    55→		avg_interactions: "Avg Interactions",
    56→		total_interactions: "Total Interactions",
    57→		avg_response_time: "Avg Response Time (sec)",
    58→		median_response_time: "Median Response Time (sec)",
    59→		avg_tokens: "Avg Tokens",
    60→		total_tokens: "Total Tokens",
    61→		avg_success_score: "Avg Success Score",
    62→		avg_errors: "Avg Errors",
    63→		total_errors: "Total Errors",
    64→	};
    65→	return labelMap[metric] || metric;
    66→}
    67→
    68→function formatDimensionValue(
    69→	value: string,
    70→	dimension: string,
    71→	userMap?: Record<string, string>,
    72→): string {
    73→	if (
    74→		dimension === "has_commit" ||
    75→		dimension === "used_plan_mode" ||
    76→		dimension === "used_skills" ||
    77→		dimension === "used_slash_commands" ||
    78→		dimension === "used_subagents"
    79→	) {
    80→		return value === "1" ? "Yes" : "No";
    81→	}
    82→
    83→	if (dimension === "project_path") {
    84→		const parts = value.split("/");
    85→		return parts[parts.length - 1] || value;
    86→	}
    87→
    88→	if (dimension === "user_id") {
    89→		return formatUsername(value, userMap);
    90→	}
    91→
    92→	return value;
    93→}
    94→
    95→export const DimensionAnalysisChart = memo(function DimensionAnalysisChart({
    96→	data,
    97→	dimension,
    98→	metric,
    99→	split_by,
   100→	showPercentage = false,
   101→	userMap,
   102→}: DimensionAnalysisChartProps) {
   103→	const { gridStroke, axisStroke } = useChartTheme();
   104→	const [hiddenSeries, setHiddenSeries] = useState<Set<string>>(new Set());
   105→	const toggleSeries = (key: string) =>
   106→		setHiddenSeries((prev) => {
   107→			const next = new Set(prev);
   108→			next.has(key) ? next.delete(key) : next.add(key);
   109→			return next;
   110→		});
   111→
   112→	const { chartData, dataKeys } = useMemo(() => {
   113→		if (!data || data.length === 0) {
   114→			return { chartData: [], dataKeys: [] };
   115→		}
   116→
   117→		let chartData: Record<string, unknown>[] = [];
   118→		let dataKeys: string[] = [];
   119→
   120→		if (split_by && data[0].split_values) {
   121→			const allSplitValues = new Set<string>();
   122→			for (const item of data) {
   123→				if (item.split_values) {
   124→					for (const key of Object.keys(item.split_values)) {
   125→						allSplitValues.add(key);
   126→					}
   127→				}
   128→			}
   129→			const rawSplitKeys = Array.from(allSplitValues);
   130→			// Map raw split keys to display names (e.g. user IDs → names)
   131→			const splitKeyDisplayMap: Record<string, string> = {};
   132→			for (const key of rawSplitKeys) {
   133→				splitKeyDisplayMap[key] = formatDimensionValue(key, split_by, userMap);
   134→			}
   135→			dataKeys = rawSplitKeys.map((key) => splitKeyDisplayMap[key]);
   136→
   137→			chartData = data.map((item) => {
   138→				const row: Record<string, unknown> = {
   139→					name: formatDimensionValue(item.dimension_value, dimension, userMap),
   140→					_fullName: item.dimension_value,
   141→					_total: 0,
   142→					_originalValues: {} as Record<string, number>,
   143→				};
   144→				const origValues = row._originalValues as Record<string, number>;
   145→				let total = 0;
   146→				for (const key of rawSplitKeys) {
   147→					const displayKey = splitKeyDisplayMap[key];
   148→					const val = item.split_values?.[key] || 0;
   149→					origValues[displayKey] = val;
   150→					total += val;
   151→				}
   152→				row._total = total;
   153→
   154→				if (showPercentage && total > 0) {
   155→					for (const key of rawSplitKeys) {
   156→						const displayKey = splitKeyDisplayMap[key];
   157→						row[displayKey] = (origValues[displayKey] / total) * 100;
   158→					}
   159→				} else {
   160→					for (const key of rawSplitKeys) {
   161→						const displayKey = splitKeyDisplayMap[key];
   162→						row[displayKey] = origValues[displayKey];
   163→					}
   164→				}
   165→
   166→				return row;
   167→			});
   168→
   169→			chartData.sort((a, b) => (b._total as number) - (a._total as number));
   170→		} else {
   171→			dataKeys = [formatMetricLabel(metric)];
   172→			chartData = data.map((item) => ({
   173→				name: formatDimensionValue(item.dimension_value, dimension, userMap),
   174→				_fullName: item.dimension_value,
   175→				[formatMetricLabel(metric)]: item.metric_value || 0,
   176→			}));
   177→
   178→			chartData.sort(
   179→				(a, b) =>
   180→					(b[formatMetricLabel(metric)] as number) -
   181→					(a[formatMetricLabel(metric)] as number),
   182→			);
