   109→		// Only add "Other" for total_errors (summable); avg metrics are not meaningful to sum
   110→		const hasOther =
   111→			metric === "total_errors" && sortedDims.length > MAX_SERIES;
   112→		const seriesKeys = hasOther ? [...topDims, "Other"] : topDims;
   113→
   114→		// Build full date range
   115→		const allDates = Array.from(new Set(data.map((item) => item.date))).sort();
   116→		const minDate = new Date(allDates[0]);
   117→		const maxDate = new Date(allDates[allDates.length - 1]);
   118→		const dateRange: string[] = [];
   119→		for (let d = new Date(minDate); d <= maxDate; d.setDate(d.getDate() + 1)) {
   120→			dateRange.push(d.toISOString().split("T")[0]);
   121→		}
   122→
   123→		const dateMap = new Map<string, Record<string, unknown>>();
   124→		for (const dateKey of dateRange) {
   125→			const dateData: Record<string, unknown> = {
   126→				date: dateKey,
   127→				displayDate: new Date(dateKey).toLocaleDateString("en-US", {
   128→					month: "short",
   129→					day: "numeric",
   130→				}),
   131→			};
   132→			for (const key of seriesKeys) {
   133→				dateData[key] = 0;
   134→			}
   135→			dateMap.set(dateKey, dateData);
   136→		}
   137→
   138→		for (const item of data) {
   139→			const dateData = dateMap.get(item.date);
   140→			if (!dateData) continue;
   141→			if (topDimsSet.has(item.dimension)) {
   142→				dateData[item.dimension] = item[metric];
   143→			} else if (hasOther) {
   144→				dateData.Other =
   145→					((dateData.Other as number) ?? 0) + ((item[metric] as number) ?? 0);
   146→			}
   147→		}
   148→
   149→		return {
   150→			seriesKeys,
   151→			chartData: Array.from(dateMap.values()).sort((a, b) =>
   152→				(a.date as string).localeCompare(b.date as string),
   153→			),
   154→		};
   155→	}, [data, metric]);
   156→
   157→	const getDisplayName = (key: string): string => {
   158→		if (key === "Other") return "Other";
   159→		if (splitBy === "user_id" && userMap) {
   160→			return userMap[key] || `${key.substring(0, 12)}...`;
   161→		}
   162→		if (splitBy === "project_path") {
   163→			const parts = key.split("/");
   164→			return parts[parts.length - 1] || key;
   165→		}
   166→		return key;
   167→	};
   168→
   169→	return (
   170→		<div className="space-y-4">
   171→			<div className="flex flex-wrap items-center justify-between gap-4">
   172→				<div className="flex items-center gap-2">
   173→					<label
   174→						htmlFor="error-metric-select"
   175→						className="text-sm font-medium text-muted"
   176→					>
   177→						Metric:
   178→					</label>
   179→					<Select
   180→						value={metric}
   181→						onValueChange={(v) => onMetricChange(v as typeof metric)}
   182→					>
   183→						<SelectTrigger className="w-56">
   184→							<SelectValue />
   185→						</SelectTrigger>
   186→						<SelectContent>
   187→							{Object.entries(METRIC_LABELS).map(([key, label]) => (
   188→								<SelectItem key={key} value={key}>
   189→									{label}
   190→								</SelectItem>
   191→							))}
   192→						</SelectContent>
   193→					</Select>
   194→				</div>
   195→
   196→				<div className="flex items-center gap-2">
   197→					<label
   198→						htmlFor="error-split-select"
   199→						className="text-sm font-medium text-muted"
   200→					>
   201→						Split:
   202→					</label>
   203→					<Select
   204→						value={splitBy}
   205→						onValueChange={(v) => onSplitByChange(v as typeof splitBy)}
   206→					>
   207→						<SelectTrigger className="w-40">
   208→							<SelectValue />
   209→						</SelectTrigger>
   210→						<SelectContent>
   211→							{Object.entries(SPLIT_LABELS).map(([key, label]) => (
   212→								<SelectItem key={key} value={key}>
   213→									{label}
   214→								</SelectItem>
   215→							))}
   216→						</SelectContent>
   217→					</Select>
   218→				</div>
   219→			</div>
   220→
   221→			<ResponsiveContainer width="100%" height={400}>
   222→				{metric === "total_errors" ? (
   223→					<BarChart
   224→						data={chartData}
   225→						margin={{ top: 10, right: 0, left: 0, bottom: 0 }}
   226→					>
   227→						<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
   228→						<XAxis
   229→							dataKey="displayDate"
   230→							tick={{ fontSize: 12 }}
   231→							angle={-45}
   232→							textAnchor="end"
   233→							height={80}
   234→							tickMargin={8}
   235→						/>
   236→						<YAxis tick={{ fontSize: 12 }} />
   237→						<Tooltip
   238→							content={(props) => (
   239→								<ChartTooltip
   240→									{...props}
   241→									nameFormatter={getDisplayName}
   242→									valueFormatter={(v) => v.toLocaleString()}
   243→								/>
   244→							)}
   245→						/>
   246→						<Legend
   247→							layout="vertical"
   248→							align="right"
   249→							verticalAlign="top"
   250→							width={160}
   251→							content={({ payload }) => (
   252→								<ChartLegend
   253→									payload={payload}
   254→									formatter={getDisplayName}
   255→									hiddenSeries={hiddenSeries}
   256→									onToggle={toggleSeries}
   257→								/>
   258→							)}
   259→						/>
   260→						{seriesKeys.map((key, index) => (
   261→							<Bar
   262→								key={key}
   263→								dataKey={key}
   264→								name={key}
   265→								stackId="1"
   266→								hide={hiddenSeries.has(key)}
   267→								fill={
   268→									key === "Other" ? OTHER_COLOR : COLORS[index % COLORS.length]
   269→								}
   270→							/>
   271→						))}
   272→					</BarChart>
   273→				) : (
   274→					<LineChart
   275→						data={chartData}
   276→						margin={{ top: 10, right: 0, left: 0, bottom: 0 }}
   277→					>
   278→						<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
   279→						<XAxis
   280→							dataKey="displayDate"
   281→							tick={{ fontSize: 12 }}
   282→							angle={-45}
   283→							textAnchor="end"
   284→							height={80}
   285→							tickMargin={8}
   286→						/>
   287→						<YAxis tick={{ fontSize: 12 }} />
   288→						<Tooltip
   289→							content={(props) => (
   290→								<ChartTooltip
   291→									{...props}
   292→									nameFormatter={getDisplayName}
   293→									valueFormatter={(v) => v.toFixed(2)}
   294→									showTotal={false}
   295→								/>
   296→							)}
   297→						/>
   298→						<Legend
   299→							layout="vertical"
   300→							align="right"
   301→							verticalAlign="top"
   302→							width={160}
   303→							content={({ payload }) => (
   304→								<ChartLegend
   305→									payload={payload}
   306→									formatter={getDisplayName}
   307→									hiddenSeries={hiddenSeries}
   308→									onToggle={toggleSeries}
   309→								/>
   310→							)}
   311→						/>
   312→						{seriesKeys.map((key, index) => (
   313→							<Line
   314→								key={key}
   315→								type="monotone"
   316→								dataKey={key}
   317→								name={key}
   318→								stroke={COLORS[index % COLORS.length]}
   319→								strokeWidth={2}
   320→								dot={{ r: 4 }}
   321→								activeDot={{ r: 6 }}
   322→								connectNulls={false}
   323→								hide={hiddenSeries.has(key)}
   324→							/>
   325→						))}
   326→					</LineChart>
   327→				)}
   328→			</ResponsiveContainer>
   329→
   330→			{seriesKeys.length === 0 && (
   331→				<div className="text-center text-sm text-muted py-4">
   332→					No error data available for the selected time period
   333→				</div>
   334→			)}
   335→		</div>
   336→	);
   337→}
